const boardModel = require('../models/boardModel');
const invitationModel = require('../models/invitationModel');
const emailService = require('./emailService');
const crypto = require('crypto');

const sendInvitation = async (boardId, inviterId, inviteeEmail) => {
  // 1. Check permission (giả sử đã có)
  // const isOwner = await boardModel.isOwner(boardId, inviterId);
  // if (!isOwner) throw new Error('Permission denied');

  // 2. Create unique token
  const token = crypto.randomBytes(20).toString('hex');

  // 3. Save invitation to DB
  const newInvitation = await invitationModel.create({
    inviterId,
    inviteeEmail,
    boardId,
    token
  });

  // 4. Send email
  const inviteLink = `https://your-app.com/invite?token=${token}`
  await emailService.send(inviteeEmail, 'Lời mời tham gia board', `Nhấp vào đây để tham gia: ${inviteLink}`);

  return newInvitation;
};

module.exports = { sendInvitation };

