import React, { useEffect, useState } from 'react';
import { useLocation, useHistory } from 'react-router-dom';
import api from '../api'; // Giả sử đã cấu hình axios instance

function useQuery() {
  return new URLSearchParams(useLocation().search);
}

const InvitationHandler = () => {
  const query = useQuery();
  const history = useHistory();
  const [message, setMessage] = useState('Đang xử lý lời mời...');

  useEffect(() => {
    const token = query.get('token');
    if (token) {
      const acceptInvite = async () => {
        try {
          const response = await api.get(`/v1/invitations/accept?token=${token}`);
          setMessage('Chấp nhận lời mời thành công! Đang chuyển hướng...');
          // Giả sử API trả về boardId để chuyển hướng
          history.push(`/boards/${response.data.boardId}`);
        } catch (error) {
          setMessage('Lỗi: Lời mời không hợp lệ hoặc đã hết hạn.');
        }
      };
      acceptInvite();
    }
  }, [query, history]);

  return <div>{message}</div>;
};

export default InvitationHandler;
